Object.keys(translations).forEach(lang => {
  const filePath = path.join(__dirname, lang, 'index.html');
  if (fs.existsSync(filePath)) {
    const html = fs.readFileSync(filePath, 'utf8');
    const dom = new JSDOM(html);
    const document = dom.window.document;
    const dict = translations[lang];

    // Replace text in all elements
    const walk = document.createTreeWalker(document.body, 4, null, false);
    let n;
    while ((n = walk.nextNode())) {
      const txt = n.nodeValue.trim();
      
      // Remove wrapping quotes for testimonials matching
      const txtUnquoted = txt.replace(/^"|"$/g, '');
      
      if (dict[txt]) {
        n.nodeValue = n.nodeValue.replace(txt, dict[txt]);
      } else if (dict[txtUnquoted]) {
        n.nodeValue = n.nodeValue.replace(txtUnquoted, dict[txtUnquoted]);
      } else if (txt === "Free forever" && n.parentNode && n.parentNode.innerHTML.includes("Free forever")) {
         n.nodeValue = n.nodeValue.replace("Free forever", dict["Free forever"]);
      }
    }
    
    // Specific fix for "Add this to your website's <head> tag:" which is mixed content
    document.querySelectorAll('p').forEach(p => {
      if (p.innerHTML.includes("Add this to your website's")) {
        const spanText = p.innerHTML;
        // Depending on language, replacing it differently, or just a simple regex to replace the string around <code>
        // For Arabic: أضف هذا إلى علامة <head> الخاصة بموقعك:
        // For German: Fügen Sie dies dem <head>-Tag Ihrer Website hinzu:
        // For Spanish: Añade esto a la etiqueta <head> de tu sitio web:
        // For French: Ajoutez ceci à la balise <head> de votre site Web :
        // For Indonesian: Tambahkan ini ke tag <head> situs web Anda:
        // For Portuguese: Adicione isso à tag <head> do seu site:
        // For Turkish: Bunu web sitenizin <head> etiketine ekleyin:
        // For Urdu: اسے اپنی ویب سائٹ کے <head> ٹیگ میں شامل کریں:
        
        let beforeTag = "";
        let afterTag = "";
        
        if (lang === 'ar') { beforeTag = "أضف هذا إلى علامة "; afterTag = " الخاصة بموقعك:"; }
        if (lang === 'de') { beforeTag = "Fügen Sie dies dem "; afterTag = "-Tag Ihrer Website hinzu:"; }
        if (lang === 'es') { beforeTag = "Añade esto a la etiqueta "; afterTag = " de tu sitio web:"; }
        if (lang === 'fr') { beforeTag = "Ajoutez ceci à la balise "; afterTag = " de votre site Web :"; }
        if (lang === 'id') { beforeTag = "Tambahkan ini ke tag "; afterTag = " situs web Anda:"; }
        if (lang === 'pt') { beforeTag = "Adicione isso à tag "; afterTag = " do seu site:"; }
        if (lang === 'tr') { beforeTag = "Bunu web sitenizin "; afterTag = " etiketine ekleyin:"; }
        if (lang === 'ur') { beforeTag = "اسے اپنی ویب سائٹ کے "; afterTag = " ٹیگ میں شامل کریں:"; }
        
        if (beforeTag) {
          p.innerHTML = `${beforeTag}<code>&lt;head&gt;</code>${afterTag}`;
        }
      }
    });

    fs.writeFileSync(filePath, dom.serialize(), 'utf8');
    console.log(`Fully translated ${lang}/index.html`);
  }
});
